#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[1000005];
    while (T--) {
        scanf("%s", s);
        long long cost0 = 0, cost1 = 0;
        int n = strlen(s);
        int i = 0;
        while (i < n) {
            char cur = s[i];
            int len = 0;
            while (i < n && s[i] == cur) { ++len; ++i; }
            if (cur == '0') {
                // this run is 0, contributes to making all 1s
                cost1 += (len < 2) ? len : 2;
            } else {
                // run of 1, contributes to making all 0s
                cost0 += (len < 2) ? len : 2;
            }
        }
        long long ans = cost0 < cost1 ? cost0 : cost1;
        printf("%lld\n", ans);
    }
    return 0;
}

