const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const s = input[idx++];
  let cost0 = 0, cost1 = 0;
  let i = 0;
  const n = s.length;
  while (i < n) {
    const cur = s[i];
    let j = i;
    while (j < n && s[j] === cur) j++;
    const len = j - i;
    if (cur === '0') {
      cost1 += (len < 2) ? len : 2;
    } else {
      cost0 += (len < 2) ? len : 2;
    }
    i = j;
  }
  results.push(String(Math.min(cost0, cost1)));
}
console.log(results.join('\n'));
